use std::collections::HashMap;

fn count_words(text: &str) -> HashMap<String, i32> {
    let mut words = HashMap::new();

    for word in text.split_whitespace() {
        let word = word.to_lowercase();
        let count = words.entry(word).or_insert(0);
        *count += 1;
    }

    words
